cat > /home/user/myproject/index.ts << 'EOF'
import { readFileSync, writeFileSync } from 'fs';
import { join } from 'path';
import 'dotenv/config';

// Mastra RAG imports
import { Mastra } from '@mastra/core';
import { createOpenAIEmbedding } from '@mastra/core';
import { PgLiteVectorStore } from '@mastra/rag';
import { createRAGPipeline } from '@mastra/rag';

async function main() {
  console.log('Starting RAG Pipeline...');

  // Initialize Mastra
  const mastra = new Mastra({});

  // Read the markdown file
  const dataPath = join(__dirname, 'data.md');
  console.log(`Reading data from: ${dataPath}`);
  const markdownContent = readFileSync(dataPath, 'utf-8');

  // Create OpenAI embedding
  const embedding = createOpenAIEmbedding({
    apiKey: process.env.OPENAI_API_KEY || '',
    modelName: 'text-embedding-3-small',
  });

  // Create vector store (using PgLite for local storage)
  const vectorStore = new PgLiteVectorStore({
    connectionString: 'file:./vector.db',
  });

  // Create RAG pipeline
  const ragPipeline = createRAGPipeline({
    embedding,
    vectorStore,
  });

  console.log('Chunking document...');
  // Chunk the document
  const chunks = await ragPipeline.chunk({
    text: markdownContent,
    chunkSize: 500,
    chunkOverlap: 50,
  });

  console.log(`Created ${chunks.length} chunks`);

  console.log('Generating embeddings and storing in vector database...');
  // Index the chunks
  await ragPipeline.index({
    documents: chunks,
    metadata: {
      source: 'data.md',
      type: 'markdown',
    },
  });

  console.log('Embeddings stored successfully');

  // Query with the specific question
  const query = 'What is the main topic of the document?';
  console.log(`Querying with: "${query}"`);

  const results = await ragPipeline.query({
    query,
    topK: 3,
  });

  console.log('Query completed');

  // Prepare output
  let output = '=== RAG Pipeline Results ===\n\n';
  output += `Query: "${query}"\n\n`;
  output += `Retrieved ${results.documents.length} chunks:\n\n`;

  results.documents.forEach((doc, index) => {
    output += `--- Chunk ${index + 1} ---\n`;
    output += `Score: ${doc.score?.toFixed(4) || 'N/A'}\n`;
    output += `Content: ${doc.content}\n`;
    output += `Metadata: ${JSON.stringify(doc.metadata)}\n\n`;
  });

  // Write output to log file
  const outputPath = join(__dirname, 'output.log');
  writeFileSync(outputPath, output, 'utf-8');

  console.log(`Results written to: ${outputPath}`);
  console.log('\n=== Output Content ===');
  console.log(output);
}

main().catch(console.error);
EOF

