import { embedMany as embedManyV2 } from '@mastra/core/dist/_types/@internal_ai-sdk-v5/dist/index.js';

async function main() {
  console.log('Starting RAG Pipeline...');

  // Read the markdown file
  const dataPath = join(__dirname, 'data.md');
  console.log(`Reading data from: ${dataPath}`);
  const markdownContent = readFileSync(dataPath, 'utf-8');

  // Create OpenAI embedding model
  const openai = createOpenAI({
    apiKey: process.env.OPENAI_API_KEY || '',
  });

  const embeddingModel = openai.embedding('text-embedding-3-small');

  // Create vector store (using LibSQL for local storage)
  const vectorStore = new LibSQLVector({
    id: 'rag-vector-store',
    url: 'file:./vector.db',
  });

  // Create a document from markdown
  console.log('Creating document from markdown...');
  const doc = MDocument.fromMarkdown(markdownContent, {
    source: 'data.md',
  });

  // Chunk the document using recursive strategy
  console.log('Chunking document...');
  await doc.chunk({
    strategy: 'recursive',
    maxSize: 500,
    overlap: 50,
  });

  const chunks = doc.getDocs();
  console.log(`Created ${chunks.length} chunks`);

  // Generate embeddings for the chunks
  console.log('Generating embeddings...');
  const chunkTexts = chunks.map(chunk => chunk.text);

  const embeddings = await embedManyV2({
    model: embeddingModel,
    values: chunkTexts,
  });

  console.log(`Generated ${embeddings.embeddings.length} embeddings`);
  console.log(`Embedding dimension: ${embeddings.embeddings[0]?.length || 'unknown'}`);

  // Create index
  const indexName = 'rag-index';
  const dimension = embeddings.embeddings[0]?.length || 1536;

  // Check if index exists, if not create it
  try {
    const indexes = await vectorStore.listIndexes();
    if (!indexes.includes(indexName)) {
      console.log(`Creating index: ${indexName}`);
      await vectorStore.createIndex({
        indexName,
        dimension,
        metric: 'cosine',
      });
    } else {
      console.log(`Index ${indexName} already exists`);
    }
  } catch (error: any) {
    console.log(`Error checking/creating index: ${error.message}`);
    // Try to create index anyway
    try {
      await vectorStore.createIndex({
        indexName,
        dimension,
        metric: 'cosine',
      });
    } catch (createError: any) {
      console.log(`Index may already exist: ${createError.message}`);
    }
  }

  // Store embeddings in vector database
  console.log('Storing embeddings in vector database...');
  const ids = await vectorStore.upsert({
    indexName,
    vectors: embeddings.embeddings,
    metadata: chunks.map((chunk, index) => ({
      text: chunk.text,
      source: 'data.md',
      chunkIndex: index,
    })),
  });

